SELECT bs."in.geometry_building_type_recs" AS geometry_building_type_recs, sum(1) AS sample_count, sum(bs.weight) AS units_count, sum(bs."out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__baseline", sum(up."out.electricity.total.energy_consumption" * bs.weight) AS "electricity.total.energy_consumption__upgrade", sum((coalesce(bs."out.electricity.total.energy_consumption", 0) - coalesce(up."out.electricity.total.energy_consumption", 0)) * bs.weight) AS "electricity.total.energy_consumption__savings", sum(bs."out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption__baseline", sum(up."out.natural_gas.total.energy_consumption" * bs.weight) AS "natural_gas.total.energy_consumption__upgrade", sum((coalesce(bs."out.natural_gas.total.energy_consumption", 0) - coalesce(up."out.natural_gas.total.energy_consumption", 0)) * bs.weight) AS "natural_gas.total.energy_consumption__savings" FROM resstock_2024_amy2018_release_2_metadata AS bs JOIN resstock_2024_amy2018_release_2_metadata AS up ON bs.bldg_id = up.bldg_id AND bs.upgrade = 0 AND up.upgrade = 1 AND up.applicability = true WHERE bs.applicability = true AND bs.upgrade = 0 AND bs."in.state" = 'CO' GROUP BY 1 ORDER BY 1